mapper.select:
		SELECT 	*
		FROM (
      	SELECT  AB.*
          , ROW_NUMBER() OVER (


		      ORDER BY  FM_KEYNO ${sortDirect}


		      ORDER BY  FM_WHERE_KEYS ${sortDirect}


		      ORDER BY  FM_COMMENTS ${sortDirect}


		      ORDER BY  FS_ORINMS ${sortDirect}


		      ORDER BY  UI_ID ${sortDirect}


		      ORDER BY  FM_REGDT ${sortDirect}


		      ORDER BY  KEYNO DESC


          ) RNUM


	      WHERE 1=1
	      AND RNUM  BETWEEN  #{firstIndex}+1 AND #{lastIndex}

SELECT FS.* , NVL2(FS_CHANGENM, (FS_FOLDER||FS_CHANGENM||'.'||FS_EXT), '') THUMBNAIL_PATH , FS_PUBLIC_PATH THUMBNAIL_PUBLIC_PATH FROM s_common_file_sub FS WHERE
FS_KEYNO = #{FS_KEYNO}
FS_FM_KEYNO = #{FS_FM_KEYNO}

